('7ca5b8e0-08ac-4ada-bca4-310683ae9166', 'Burrata Salad', 'Salads', 'capiche', null, null, null, 1, 'approved', 164.65, 164.65, 620, 0, 5, false, 250, 'Gram', 1, ARRAY['Toss leaves with vinaigrette & salt.','Add cherry tomato, grapefruit, olives.','Place burrata in centre.','Arrange salad mix around.','Sprinkle pine nuts; drizzle olive oil & hot honey.','Garnish with edible flowers.']::text[], null, null, '2026-06-20T09:30:00.000Z', null, '2026-06-01T09:00:00.000Z', '2026-06-01T09:00:00.000Z'),
('eefc963b-505a-4d4c-adf9-55d314b74b11', 'Caesar Salad', 'Salads', 'capiche', null, null, null, 1, 'approved', 41.12, 41.12, 480, 0, 5, false, 200, 'Gram', 1, ARRAY['Tear leaves.','Slice onion rings.','Toss lettuce with mayo, salt, pepper.','Add parmesan and croutons.','Check seasoning.','Plate; garnish with onion rings.']::text[], null, null, '2026-06-20T09:30:00.000Z', null, '2026-06-01T09:00:00.000Z', '2026-06-01T09:00:00.000Z'),
('cc1723c2-1b95-40f9-bcee-d04983501ef1', 'Persimmon Salad', 'Salads', 'capiche', null, null, null, 1, 'approved', 187.23, 187.23, null, 0, 5, false, 265, 'Gram', 1, ARRAY['Toss arugula with vinaigrette; do not overdress.','Arrange on chilled serving plate.','Place persimmon and strawberry evenly over greens.','Add burrata as soft dollops; season lightly.','Spoon caviar on burrata; sprinkle pine nuts and edible flowers.','Drizzle hot honey; serve immediately.']::text[], null, null, '2026-06-20T09:30:00.000Z', null, '2026-06-01T09:00:00.000Z', '2026-06-01T09:00:00.000Z'),
('258354ad-6584-4dfa-af74-6faf08bcb45a', 'Summer Burrata Salad', 'Salads', 'capiche', null, null, null, 1, 'approved', 141.38, 141.38, 680, 0, 5, false, 344.5, 'Gram', 1, ARRAY['Process iceberg lettuce, romaine lettuce, and Lollo Rosso. Give them an ice bath to keep them crisp.','In a large bowl, combine all processed leaves. Add salt, black pepper, and vinaigrette. Add arugula and toss well.','Cut mango and grapefruit into cubes.','Plate the mixed leaves. Place a burrata on top.','Drizzle olive oil over the burrata and add crushed black pepper.','Arrange cubed mango, grapefruit, and cherry tomatoes around the burrata. Add edible flowers.','Scatter roasted hazelnuts and chopped granola.','Finish with a drizzle of hot honey.']::text[], null, null, '2026-06-20T09:30:00.000Z', null, '2026-06-01T09:00:00.000Z', '2026-06-01T09:00:00.000Z'),
('68632715-090d-4c62-a348-1963b03a4e9f', 'Roasted Red Bell Pepper Soup', 'Soups', 'capiche', null, null, null, 1, 'approved', 20.24, 20.24, null, 0, 5, false, 370, 'Gram', 1, ARRAY['Roast veg until soft/charred; cool. Peel peppers if desired.','Blend smooth; strain if desired. Chili; portion 120 g per serve.','Melt a little CDP butter; add 120 g paste, sauté 1 min. Add 160 g water; season; add sour cream; simmer low 3–4 min.','Spread 5 g garlic butter on 70 g sourdough; toast until crisp.','Bowl soup; swirl pesto; sprinkle sesame. Serve hot with bread.']::text[], null, null, '2026-06-20T09:30:00.000Z', null, '2026-06-01T09:00:00.000Z', '2026-06-01T09:00:00.000Z'),
('0323118f-8534-405c-ba81-9cf3394a025c', 'Arancini', 'Appetiser', 'capiche', null, null, null, 6, 'approved', 48.04, 48.04, 480, 0, 5, false, 117, 'Gram', 1, ARRAY['Prepare rice mix; cool completely.','Weigh 16 g rice mix, add 3 g mozzarella, shape into ball (~19 g). Repeat for 6.','Dip into batter.','Coat with panko crumbs.','Deep fry at 180 °C for ~4–5 min; core ≈ 74 °C.','Drain; plate with hot mayo & green garlic.']::text[], null, null, '2026-06-20T09:30:00.000Z', null, '2026-06-01T09:00:00.000Z', '2026-06-01T09:00:00.000Z'),
('29b3ab01-6dc4-4532-9c3d-06a66acd3428', 'Dough Balls', 'Appetiser', 'capiche', null, null, null, 1, 'approved', 97.65, 97.65, 540, 0, 5, false, 150, 'Gram', 1, ARRAY['Divide dough into 6–8 × ~20 g balls.','Roll and place on screen.','Bake at 350 °C ~2 min until puffed.','Toss in melted butter, garlic, parsley.','Garnish with green garlic.','Serve immediately.']::text[], null, null, '2026-06-20T09:30:00.000Z', null, '2026-06-01T09:00:00.000Z', '2026-06-01T09:00:00.000Z'),
('b161c44b-0aca-438c-8b61-b358a3cdfc30', 'Garlic Bread', 'Appetiser', 'capiche', null, null, null, 1, 'approved', 51.42, 51.42, 540, 0, 5, false, 105, 'Gram', 1, ARRAY['Bake base; cool slightly.','Deep cut into 8 wedges.','Stuff cream cheese between cuts.','Brush with butter + chopped garlic.','Microwave 30 s.','Bake at 350 °C for 2 min until golden; garnish green garlic.']::text[], null, null, '2026-06-20T09:30:00.000Z', null, '2026-06-01T09:00:00.000Z', '2026-06-01T09:00:00.000Z'),
('c90c215d-2f01-4b22-ba5c-f4885c87445b', 'Pasta Fritti 2.0', 'Pasta', 'capiche', null, null, null, 1, 'approved', 131.76, 131.76, null, 0, 5, false, 547, 'Gram', 1, ARRAY['Mix all filling ingredients well.','Cut pasta sheets into 1 x 4 pieces.','Spread ricotta filling, place mozzarella stick and a line of tomato paste. Roll tightly.','Freeze for 15 min.','Dip in batter; coat with bread crumbs.','Deep fry at 160-180 °C for 4-5 min; finish in oven 10-15 sec.','Grate parmesan; top with green garlic.','Serve with garlic ranch & hot tomato sauce.']::text[], null, null, '2026-06-20T09:30:00.000Z', null, '2026-06-01T09:00:00.000Z', '2026-06-01T09:00:00.000Z'),
('f56144ae-65e5-43d1-9fe8-c988734e5ae7', 'Butter Garlic Mushroom', 'Pasta', 'capiche', null, null, null, 1, 'approved', 115.34, 115.34, 540, 0, 5, false, 250, 'Gram', 1, ARRAY['Heat oil; cook mushrooms.','Add garlic; sauté.','Add basil, parsley; season.','Toss with vinaigrette & chilli flakes.','Add butters.','Serve hot.']::text[], null, null, '2026-06-20T09:30:00.000Z', null, '2026-06-01T09:00:00.000Z', '2026-06-01T09:00:00.000Z'),
('4359e640-af7b-4114-880f-4f48972f69a5', 'Saucy Brussels Sprouts', 'Vegetable', 'capiche', null, null, null, 1, 'approved', 165.74, 165.74, 580, 0, 5, false, 676, 'Gram', 1, ARRAY['Heat olive oil in a pan. Add Brussels sprouts (cut in halves) and char on high heat.','Add butter, garlic, chilli flakes, salt, pepper, and balsamic vinegar. Toss well.','In another pan, combine cream cheese, béchamel, sour cream, mayonnaise, salt, and black pepper. Cook on low heat until smooth.','Spread the cream cheese sauce on a plate and place the charred Brussels sprouts on top.','Garnish with fresh Bhavnagri chilli, pickled onions, and feta crumbles.']::text[], null, null, '2026-06-20T09:30:00.000Z', null, '2026-06-01T09:00:00.000Z', '2026-06-01T09:00:00.000Z'),
('6ee42b65-efe1-4011-91de-ba831cc4b1e9', 'Miso Tomato Soup', 'Soups', 'capiche', null, null, null, 1, 'approved', 47.14, 47.14, 440, 0, 5, false, 1093, 'Gram', 1, ARRAY['Heat olive oil in a pot, add onion, garlic, carrot, chili, thyme, bay leaf, parsley stems. Sauté until soft and lightly golden.','Add tomatoes, cook down until jammy.','Add water and stock powder, simmer 20 min.','Remove bay leaf and thyme stems. Blend until smooth.','Take off heat, whisk in miso paste.','Adjust seasoning with soy, salt, and pepper.','Stir in chopped fresh basil just before serving.']::text[], null, null, '2026-06-20T09:30:00.000Z', null, '2026-06-01T09:00:00.000Z', '2026-06-01T09:00:00.000Z'),
('63ef313b-1215-4276-a50f-26061bba6f1f', 'Pomodoro Spaghetti', 'Pasta', 'capiche', null, null, null, 1, 'approved', 102.17, 102.17, 740, 0, 5, false, 250, 'Gram', 1, ARRAY['Heat oil; sauté cherry tomatoes.','Add pomodoro; season.','Add spaghetti; toss.','Simmer; add butter.','Finish with basil; parmesan garnish.']::text[], null, null, '2026-06-20T09:30:00.000Z', null, '2026-06-01T09:00:00.000Z', '2026-06-01T09:00:00.000Z'),
('f26c88ca-223f-4a93-906f-0a528f12ca18', 'Spicy Tomato & Cream Macaroni', 'Pasta', 'capiche', null, null, null, 1, 'approved', 71.94, 71.94, 740, 0, 5, false, 250, 'Gram', 1, ARRAY['Heat butter; add hot sauce; season.','Add orange sauce; stir.','Add cream; adjust seasoning.','Toss macaroni; serve.']::text[], null, null, '2026-06-20T09:30:00.000Z', null, '2026-06-01T09:00:00.000Z', '2026-06-01T09:00:00.000Z'),
('cc25b2b7-aae3-40d8-9c7e-9c500b1b990e', 'Alfredo Fettuccine', 'Pasta', 'capiche', null, null, null, 1, 'approved', 71.69, 71.69, 740, 0, 5, false, 250, 'Gram', 1, ARRAY['Heat oil & butter; add garlic, herbs.','Add béchamel; season; adjust with water.','Toss fettuccine; finish with parmesan.']::text[], null, null, '2026-06-20T09:30:00.000Z', null, '2026-06-01T09:00:00.000Z', '2026-06-01T09:00:00.000Z'),
('fd3ac271-379f-4cf8-8ffc-13d3e51e047f', 'Lemon Linguini', 'Pasta', 'capiche', null, null, null, 1, 'approved', 125.6, 125.6, null, 0, 5, false, 250, 'Gram', 1, ARRAY['Heat butter; add white sauce, mascarpone.','Add lemon; season.','Toss linguini; adjust with water.','Finish with basil; parmesan.']::text[], null, null, '2026-06-20T09:30:00.000Z', null, '2026-06-01T09:00:00.000Z', '2026-06-01T09:00:00.000Z'),
('f143a3ab-602d-4ea5-97a8-500e8fa2d775', 'Risotto', 'Pasta', 'capiche', null, null, null, 1, 'approved', 134.96, 134.96, 780, 0, 5, false, 250, 'Gram', 1, ARRAY['Heat butter+oil; sauté garlic, asparagus, peas.','Add rice; season.','Add water; add béchamel.','Finish with parmesan; serve.']::text[], null, null, '2026-06-20T09:30:00.000Z', null, '2026-06-01T09:00:00.000Z', '2026-06-01T09:00:00.000Z'),
('ff7f878b-6441-4686-bd2d-20c229281520', 'Lasagna', 'Pasta', 'capiche', null, null, null, 7, 'approved', 143.63, 143.63, 740, 0, 5, false, 1300, 'Gram', 1, ARRAY['Heat oil in a pan; sauté onion, carrot, celery and garlic until soft.','Add soaked and drained soy chunks; cook for 3–4 min.','Add tomato passata, tomato paste, oregano, salt and pepper. Simmer 15–20 min.','Make béchamel: melt butter, add flour; cook 1 min. Gradually whisk in milk. Cook until thick. Season with salt and nutmeg.','In a baking dish, layer: bolognese sauce, sheets, béchamel, mozzarella. Repeat layers. Top with parmesan.','Bake at 180°C for 40–45 min or until golden and bubbling. Rest 10 min before serving.']::text[], null, null, '2026-06-20T09:30:00.000Z', null, '2026-06-01T09:00:00.000Z', '2026-06-01T09:00:00.000Z'),
('c69f89f0-2136-4fe2-9e58-a3b66d1aa934', 'Stuffed Conchiglioni', 'Pasta', 'capiche', null, null, null, 1, 'approved', 103.03, 103.03, 780, 0, 5, false, 662, 'Gram', 1, ARRAY['Mix ricotta, cream cheese, blanched kale, chopped jalapeño, salt and xanthan gum into a smooth, well-seasoned filling.','Stuff each boiled conchiglioni generously with the kale-ricotta filling.','Spoon garlic pomodoro sauce as a base in a shallow oven dish.','Arrange stuffed shells on the sauce base.','Sprinkle parmesan and red paprika on top.','Bake at 350°C for 6 min until golden and heated through.','Garnish with slit onion and sunflower seeds.']::text[], null, null, '2026-06-20T09:30:00.000Z', null, '2026-06-01T09:00:00.000Z', '2026-06-01T09:00:00.000Z'),
('26298e9f-4f05-470d-9ad2-0ea9e7501553', 'Caramelised Onion Pasta', 'Pasta', 'capiche', null, null, null, 1, 'approved', 62.24, 62.24, 780, 0, 5, false, 329, 'Gram', 1, ARRAY['Heat olive oil in a pan over medium heat.','Add chopped garlic and sauté until fragrant.','Add caramelised onion and cook for 1–2 min.','Add 1 ladle of water; bring to a gentle simmer.','Add spaghetti and mix well to coat.','Add mix seasoning, fresh cream and soya sauce. Toss until pasta is creamy and well combined.','Adjust consistency with water if needed.','Finish with chilli crisp and parmesan. Toss to combine.','Plate and garnish with fresh parsley. Serve immediately.']::text[], null, null, '2026-06-20T09:30:00.000Z', null, '2026-06-01T09:00:00.000Z', '2026-06-01T09:00:00.000Z'),
('80629ffb-6a18-468e-9f1a-6c9039c31678', 'Pink Burrata Pasta', 'Pasta', 'capiche', null, null, null, 1, 'approved', 124.8, 124.8, 780, 0, 5, false, 247, 'Gram', 1, ARRAY['Roast beetroot with olive oil wrapped in foil paper. Once roasted, strain and blend into a purée.','Heat a pan. Add pesto white sauce.','Add farfalle pasta. Season with black pepper, chilli flakes, butter, and salt. Mix well.','Add beetroot purée and toss until the sauce turns pink.','Plate and garnish with a smashed burrata dollop, crushed pumpkin seeds and pistachios, olive oil, and crushed black pepper.']::text[], null, null, '2026-06-20T09:30:00.000Z', null, '2026-06-01T09:00:00.000Z', '2026-06-01T09:00:00.000Z'),
('f6144a54-e65c-4175-a050-5fce8f7ff11c', 'Tomato Butter Risotto', 'Risotto', 'capiche', null, null, null, 1, 'approved', 109.5, 109.5, 740, 0, 5, false, 256, 'Gram', 1, ARRAY['Heat olive oil in a pan. Add garlic and onion and sauté until softened.','Add pomodoro sauce, water, salt, and black pepper. Stir well.','Add risotto rice and butter. Cook well, stirring frequently. Finish with Parmesan.','Plate and garnish with confit cherry tomatoes, a pesto dollop, arugula, and chopped kalonji.']::text[], null, null, '2026-06-20T09:30:00.000Z', null, '2026-06-01T09:00:00.000Z', '2026-06-01T09:00:00.000Z'),
('77cb78a7-d27e-450d-87ad-d842dd285000', 'Truffle Mac & Cheese', 'Pasta', 'capiche', null, null, null, 1, 'approved', 164.71, 164.71, 840, 0, 5, false, 253, 'Gram', 1, ARRAY['Heat a pan. Add béchamel sauce, cheddar cheese, and mozzarella cheese. Melt together.','Add boiled pasta and mix well. Season with salt and black pepper. Add parmesan and butter.','Transfer into a steel plate. Top with cheddar cheese, mozzarella cheese, and parmesan. Bake in oven.','Remove from oven. Garnish with truffle oil, truffle pâté, and spring onion.']::text[], null, null, '2026-06-20T09:30:00.000Z', null, '2026-06-01T09:00:00.000Z', '2026-06-01T09:00:00.000Z'),
('792d14ed-5317-43ed-9c61-b70a4de87d5f', 'Sticky Toffee Pudding', 'Desserts', 'capiche', null, null, null, 1, 'approved', 52.6, 52.6, 600, 0, 5, false, 215, 'Gram', 1, ARRAY['Bake pudding.','Warm pudding before service.','Plate pudding.','Pour caramel sauce.','Add pecan ice cream.','Serve immediately.']::text[], null, null, '2026-06-20T09:30:00.000Z', null, '2026-06-01T09:00:00.000Z', '2026-06-01T09:00:00.000Z'),
('245a49a2-3d4e-45cc-b94a-6c70060b33b7', 'Brownie With Ice Cream', 'Desserts', 'capiche', null, null, null, 1, 'approved', 108.15, 108.15, 640, 0, 5, false, 185, 'Gram', 1, ARRAY['Bake and portion brownies.','Warm before serving.','Plate brownie.','Add ice cream scoop.','Drizzle Nutella.','Garnish tuile.']::text[], null, null, '2026-06-20T09:30:00.000Z', null, '2026-06-01T09:00:00.000Z', '2026-06-01T09:00:00.000Z'),
