('f8764972-d121-4f0f-8386-81385a9d33c8', 'Moscow Mule', 'Drinks', 'capiche', null, null, null, 1, 'approved', 91.7, 91.7, 360, 0, 5, false, 320, 'Gram', 1, ARRAY['Fill mule mug with cubed ice.','Add lemon juice and ginger zest into mug.','Add ginger beer to 320 ml; stir gently with bar spoon; lift once.','Garnish with lemon wheel and rosemary sprig.']::text[], null, null, '2026-06-20T09:30:00.000Z', null, '2026-06-01T09:00:00.000Z', '2026-06-01T09:00:00.000Z'),
('c73316f5-8929-46fe-ba06-1a83791d7703', 'Sunset Cocktail', 'Drinks', 'capiche', null, null, null, 1, 'approved', 67.54, 67.54, 300, 0, 5, false, 230, 'Gram', 1, ARRAY['Glass & ice (0:00–0:10): Fill bamboo glass with cubed ice.','Build (0:10–0:30): Add lemon juice, orange juice, and hibiscus syrup.','Top (0:30–0:55): Add Sprite to 230 ml; pour gently over the back of a spoon for a layered effect; gentle lift.','Garnish & QC (0:55–1:15): Garnish with fresh jalapeño slice on rim.']::text[], null, null, '2026-06-20T09:30:00.000Z', null, '2026-06-01T09:00:00.000Z', '2026-06-01T09:00:00.000Z'),
('5baf780e-ef1c-41f9-a592-fad1c4bc8889', 'Tamarind Fizz', 'Drinks', 'capiche', null, null, null, 1, 'approved', 56.97, 56.97, 300, 0, 5, false, 220, 'Gram', 1, ARRAY['Glass & ice (0:00–0:10): Fill bamboo glass with cubed ice.','Build (0:10–0:25): Add tamarind syrup and salt.','Top (0:25–0:50): Top with Schweppes Ginger Ale to 220 ml; stir gently; lift once.','Garnish & QC (0:50–1:15): Garnish with basil.']::text[], null, null, '2026-06-20T09:30:00.000Z', null, '2026-06-01T09:00:00.000Z', '2026-06-01T09:00:00.000Z'),
('b6a29a68-0e0e-49ab-bc49-9e6e5a2bd14c', 'Tom Yum', 'Soups', 'aiko', null, null, null, 1, 'approved', 17.46, 17.46, 360, 13.12, 5, false, 198, 'Gram', 1, ARRAY['Blend chilli, onion, garlic, mushroom to coarse paste.','Cook paste until aromatic.','Add tamarind, water, vinegar, sugar; simmer 8-10 min.','Adjust hot-sour balance as per standard.']::text[], null, null, '2026-06-20T09:30:00.000Z', null, '2026-06-01T09:00:00.000Z', '2026-06-01T09:00:00.000Z'),
('9e17407d-2aeb-4f04-8ed7-2a2685306009', 'Thai Spring Roll', 'Appetiser', 'aiko', null, null, null, 1, 'approved', 4.41, 4.41, null, 0, 5, false, 196.75, 'Gram', 1, ARRAY['Place approximately 30 g Thai spring filling on each spring roll sheet.','Roll tightly while folding the sides inward. Seal the edge using slurry/water if required.','Heat oil to 170-175°C. Carefully fry spring rolls until golden brown and crispy.','Remove and drain excess oil on absorbent paper.','Serve spring rolls as entire pieces. Drizzle with sriracha sauce. Garnish with spring onion slit.']::text[], null, null, '2026-06-20T09:30:00.000Z', null, '2026-06-01T09:00:00.000Z', '2026-06-01T09:00:00.000Z'),
('c8bebfef-f84b-4561-881e-e22c70f213d3', 'Kwispy Lotus Root', 'Sides', 'aiko', null, null, null, 1, 'approved', 32.05, 32.05, 460, 0, 5, false, 166, 'Gram', 1, ARRAY['Fry lotus root until crisp; drain well.','Heat wok; add garlic + chilli; sauté briefly.','Add onion + bell pepper; toss 30–40 sec.','Add sauce + pok choy; bring to bubble.','Add lotus root; toss quickly to coat.','Finish spring onion + basil; plate immediately.']::text[], null, null, '2026-06-20T09:30:00.000Z', null, '2026-06-01T09:00:00.000Z', '2026-06-01T09:00:00.000Z'),
('1efa6516-30ee-46b6-9a80-2458a85ba92e', 'Kwispy Wonton', 'Appetiser', 'aiko', null, null, null, 1, 'approved', 33.04, 33.04, 460, 0, 5, false, 96, 'Gram', 1, ARRAY['Place approx. 15 g of Kwispy Wonton filling in the center of each gyoza skin.','Apply corn slurry on the edges. Fold and seal tightly in desired shape.','Heat oil to 170–175°C. Carefully drop wontons into hot oil.','Fry for 3–4 minutes or until golden brown and crispy.','Remove and drain excess oil on paper towel.']::text[], null, null, '2026-06-20T09:30:00.000Z', null, '2026-06-01T09:00:00.000Z', '2026-06-01T09:00:00.000Z'),
('4767cf73-dc28-4954-822b-c32d700517f3', 'Tteokbokki', 'Sides', 'aiko', null, null, null, 1, 'approved', 108.6, 108.6, 540, 0, 5, false, 170.13, 'Gram', 1, ARRAY['Blanch rice cakes until soft; drain well.','Heat pan; add water + sauce; bring to simmer.','Add rice cakes; toss to coat.','Add salt, MSG, sugar; reduce until glossy.','Finish spring onion + fried garlic; garnish with spring onion slit.']::text[], null, null, '2026-06-20T09:30:00.000Z', null, '2026-06-01T09:00:00.000Z', '2026-06-01T09:00:00.000Z'),
('36f46b15-dd34-4f49-870b-d646d1589e2f', 'Tofu Bao', 'Dimsum', 'aiko', null, null, null, 1, 'approved', 40.95, 40.95, 540, 0, 5, false, 223, 'Gram', 1, ARRAY['Mise en place: Keep all ingredients measured and ready. Slice cucumber into thin strips. Prepare coleslaw chilled. Heat oil to 170-175°C. Steam bao until soft and warm.','Coat tofu evenly with tofu batter.','Deep fry at 170-175°C until golden brown and crispy.','Remove and drain excess oil on absorbent paper.','Open warm bao carefully without tearing.','Spread bao sauce base evenly inside the bao.','Add coleslaw followed by crispy tofu.','Place cucumber strips neatly on top.','Garnish with black & white sesame.','Serve immediately while bao is warm and tofu is crispy.']::text[], null, null, '2026-06-20T09:30:00.000Z', null, '2026-06-01T09:00:00.000Z', '2026-06-01T09:00:00.000Z'),
('6bc39452-df8f-4f8b-bfe1-dab71079954b', 'General Tso''s Water Chestnuts', 'Sides', 'aiko', null, null, null, 1, 'approved', 81.22, 81.22, 540, 0, 5, false, 318, 'Gram', 1, ARRAY['Coat water chestnut with flour; shake off excess. Deep fry until golden and crispy; drain.','Heat wok on high flame. Add chopped garlic, Thai red chilli and onion; stir-fry until aromatic.','Add yellow and red bell peppers; stir-fry until slightly soft yet crunchy.','Add sauces (gyoza dip + drunken sauce); bring to a simmer and stir until the glaze thickens.','Add fried water chestnuts and spring onion; toss quickly to coat. Finish with basil. Transfer to serving bowl. Garnish with fried spring roll strips.']::text[], null, null, '2026-06-20T09:30:00.000Z', null, '2026-06-01T09:00:00.000Z', '2026-06-01T09:00:00.000Z'),
('936fe5de-002c-43f1-820d-bb43a39264b1', 'Steamed Edamame (Chilli / Salted)', 'Sides', 'aiko', null, null, null, 1, 'approved', 104.77, 104.77, 540, 0, 5, false, 172, 'Gram', 1, ARRAY['Steam edamame with pods until tender and hot. Drain any excess water.','Transfer steamed edamame to a bowl.','For chilli version: Add chilli crisp and toss evenly to coat. For salted version: Add salt and toss evenly to coat.','Serve hot immediately.']::text[], null, null, '2026-06-20T09:30:00.000Z', null, '2026-06-01T09:00:00.000Z', '2026-06-01T09:00:00.000Z'),
('0ca27d5b-07c5-411f-b3c7-2075fda3ccc2', 'Korean Mandu', 'Sides', 'aiko', null, null, null, 1, 'approved', 52.77, 52.77, 540, 0, 5, false, 106, 'Gram', 1, ARRAY['Prepare Korean Mandu filling (see filling method below). Allow to cool completely.','Place 1 portion (approx. 75 g) of filling in the center of the gyoza skin.','Moisten edges with water. Fold and pleat to seal securely.','Heat oil to 175°C. Fry mandu until golden brown and crisp, about 3–4 minutes. Drain excess oil.','Drizzle spicy mayo and coriander mayo over mandu.','Garnish with toasted white sesame seeds and julienne cut nori sheets.','Serve hot immediately.']::text[], null, null, '2026-06-20T09:30:00.000Z', null, '2026-06-01T09:00:00.000Z', '2026-06-01T09:00:00.000Z'),
('34f7e885-96d4-49bf-a80a-e11e9eda2775', 'Creamy Corn Rocks', 'Sides', 'aiko', null, null, null, 1, 'approved', 71.65, 71.65, 580, 0, 5, false, 244, 'Gram', 1, ARRAY['Heat corn rocks sauce in a pan over medium heat.','Add water and stir well to adjust the consistency. Bring to a simmer.','Add fried corn and toss to coat evenly with the sauce.','Cook for 1–2 minutes until the sauce clings to the corn and is creamy.','Transfer to a bowl.','Garnish with chopped black sesame seeds, spring onion and pickled red paprika slices. Serve hot immediately.']::text[], null, null, '2026-06-20T09:30:00.000Z', null, '2026-06-01T09:00:00.000Z', '2026-06-01T09:00:00.000Z'),
('4c5805bb-5344-4653-877c-3e03c3727bcc', 'Kwispy Scallion Pancake', 'Sides', 'aiko', null, null, null, 1, 'approved', 9.18, 9.18, null, 0, 5, false, 267, 'Gram', 1, ARRAY['Prepare all components as per recipes below.','Cook scallion pancake until golden brown and crispy on both sides.','Heat Sichuan soy glaze and brush over the pancake.','Drizzle green garlic cream cheese and sriracha sauce over the top.','Top with scallion salad.','Sprinkle toasted white sesame seeds.','Slice or serve whole.','Serve hot immediately.']::text[], null, null, '2026-06-20T09:30:00.000Z', null, '2026-06-01T09:00:00.000Z', '2026-06-01T09:00:00.000Z'),
('68dcdc82-39e0-49ac-96da-f397568bedb5', 'Cold Spicy Sesame Noodles', 'Noodles', 'aiko', null, null, null, 1, 'approved', 71.18, 71.18, 640, 0, 5, false, 260, 'Gram', 1, ARRAY['Cook soba noodles as per package instructions. Rinse in cold water and drain well.','In a bowl, add cold spicy sesame sauce and place the noodles. Toss well to coat evenly.','Arrange cucumber slices, carrot slices and mix iceberg romaine on the side of the plate.','Place the sauced noodles in the center.','Top with white part spring onion, crushed peanuts and fried sesame.','Serve immediately. Keep chilled until serving.']::text[], null, null, '2026-06-20T09:30:00.000Z', null, '2026-06-01T09:00:00.000Z', '2026-06-01T09:00:00.000Z'),
('3ec5bdba-af0c-493c-b00e-21da686ae3cb', 'Tokyo Style Pizza (Dough Base)', 'Pizza', 'aiko', null, null, null, 1, 'approved', 422.91, 422.91, null, 0, 5, false, 150, 'Gram', 1, ARRAY['Combine water and dry yeast.','Add flour and mix until shaggy.','Cover loosely and ferment 12–16 h at room temp.','Add fermented biga in mixer.','Add cold water gradually.','Add flour and dry yeast; mix.','Add salt; mix 4–5 min.','Drizzle EVOO; mix smooth (windowpane test).','Rest 1–2 h.','Divide into 150 g balls.','Place in oiled trays; cover.','Cold-ferment (CF) 48 h.','Remove dough; temper 1 h.','Spread/stretch dough evenly.','Apply pizza sauce evenly.','Top evenly with cheese and desired toppings.','Bake in a preheated oven until crust is blistered and golden.','Finish with fresh basil after baking.']::text[], null, null, '2026-06-20T09:30:00.000Z', null, '2026-06-01T09:00:00.000Z', '2026-06-01T09:00:00.000Z'),
('860950a9-f3b1-45f4-b574-c2382be65a14', 'Katsu Curry', 'Mains', 'aiko', null, null, null, 1, 'approved', 36.46, 36.46, 580, 0, 5, false, 481, 'Gram', 1, ARRAY['Heat katsu curry gently (do not boil).','Heat tofu if required.','Plate rice.','Arrange tofu, pour curry.','Garnish cabbage, cucumber, sesame, togarashi.','Finish scallion oil + unagi.']::text[], null, null, '2026-06-20T09:30:00.000Z', null, '2026-06-01T09:00:00.000Z', '2026-06-01T09:00:00.000Z'),
('3c4d4998-37fd-42ee-ac9e-54e4559ab8e7', 'Thai Curry', 'Mains', 'aiko', null, null, null, 1, 'approved', 131.54, 131.54, 580, 0, 5, false, 961, 'Gram', 1, ARRAY['Cook green paste 60-90 sec until aromatic.','Add coconut milk and water; simmer gently.','Add vegetables and cook until just tender.','Season with MSG, white pepper and stock powder.','Serve with rice; finish with scallion oil, chilli oil, sesame mix and lotus stem.']::text[], null, null, '2026-06-20T09:30:00.000Z', null, '2026-06-01T09:00:00.000Z', '2026-06-01T09:00:00.000Z'),
('092482c9-d332-4759-a77f-22fc38885554', 'Sri Lankan Curry', 'Mains', 'aiko', null, null, null, 1, 'approved', 113.54, 113.54, null, 0, 5, false, 507.5, 'Gram', 1, ARRAY['Heat oil in a pan.','Add Kashmiri chilli powder, Kashmiri chilli red paste and Sri Lankan red paste. Sauté until aromatic.','Add tamarind water and stir well.','Pour in coconut milk, stock water and water. Mix and bring to a simmer.','Season with MSG, salt, white pepper, stock powder and fresh Sri Lankan red curry powder mix.','Add tofu, carrot, mushroom and shimeji mushroom. Cook until vegetables are tender.','Add picked red paprika and slit onion. Simmer for 1-2 minutes.','Finish with red chilli oil.','Garnish with basil leaves and fried onion.','Serve hot.']::text[], null, null, '2026-06-20T09:30:00.000Z', null, '2026-06-01T09:00:00.000Z', '2026-06-01T09:00:00.000Z'),
('e4b548d9-da72-456b-b7c0-2474d837fe4b', 'Custom Stir Fry', 'Mains', 'aiko', null, null, null, 1, 'approved', null, null, null, 0, 5, false, 5256.1, 'Gram', 1, ARRAY['Heat wok until smoking hot.','Add oil and aromatics.','Add selected vegetables.','Toss on high flame.','Add preferred sauce.','Cook until vegetables remain crisp tender.','Finish with garnish selection.','Serve immediately hot.']::text[], null, null, '2026-06-20T09:30:00.000Z', null, '2026-06-01T09:00:00.000Z', '2026-06-01T09:00:00.000Z'),
('b2b6df10-3359-4527-93f0-e643f4d0f89a', 'Chestnut Gyoza', 'Dimsum', 'aiko', null, null, null, 6, 'approved', 64.05, 64.05, 540, 0, 5, false, 793, 'Gram', 1, ARRAY['Prepare filling: mix/chop chestnut with chillies and onion. Cook until aromatic.','Season with stock powder, MSG, white pepper, salt.','Add slurry; cook until mixture binds. Cool completely.','Fill wrappers with 18 g filling; pleat tightly.','Pan-fry gyoza in oil until base golden.','Add water, cover and steam 4–5 min.','Remove lid; re-crisp base 30–45 sec.']::text[], null, null, '2026-06-20T09:30:00.000Z', null, '2026-06-01T09:00:00.000Z', '2026-06-01T09:00:00.000Z'),
('424a8be3-fe96-4e81-9c77-1c2801205f94', 'Okonomiyaki Gyoza (6 Pcs)', 'Dimsum', 'aiko', null, null, null, 6, 'approved', 113.7, 18.95, null, 0, 5, false, 894, 'Gram', 1, ARRAY['Cook stages 1→4 sequentially; dry the mix fully. Fold in pickled ginger and tempura flakes.','Fill gyoza skins with filling; pleat tightly (18 g filling per gyoza).','Heat non-stick pan; add oil. Place gyoza; pan-fry until base golden.','Add water, cover and steam for 4–5 minutes.','Remove lid; re-crisp base for 30–45 seconds.','Plate in a fan pattern.','Drizzle mustard mayo and soy-ketchup glaze.','Garnish with chilli, spring onion and sesame.']::text[], null, null, '2026-06-20T09:30:00.000Z', null, '2026-06-01T09:00:00.000Z', '2026-06-01T09:00:00.000Z'),
('1205cda2-0f5d-4599-a30e-f7d228d1fd1d', 'Truffle Edamame Dimsums', 'Dimsum', 'aiko', null, null, null, 4, 'approved', 138.89, 138.89, 840, 0, 5, false, 358, 'Gram', 1, ARRAY['Pulse edamame to coarse mince.','Mix with cream cheese, salt, pepper, truffle oil, truffle pate; add water to adjust texture.','Fill wrappers evenly and seal.','Steam 4–5 minutes until cooked.']::text[], null, null, '2026-06-20T09:30:00.000Z', null, '2026-06-01T09:00:00.000Z', '2026-06-01T09:00:00.000Z'),
('9cf5ba51-ea00-4ad6-b668-a9394b7b44b6', 'Saucy Momos', 'Dimsum', 'aiko', null, null, null, 5, 'approved', 39.31, 39.31, 480, 0, 5, false, 1500, 'Gram', 1, ARRAY['Sauté onion until translucent.','Add cabbage and carrot; cook on high flame until moisture evaporates.','Add spring onion and silken tofu.','Add salt, white pepper, MSG and stock powder.','Mix well and cook until dry.','Cool completely before shaping.','Place required filling in the center of each wrapper.','Pleat and seal properly.','Ensure no leakage and even shape.','Place momos in steamer.','Steam for 4–5 minutes until fully cooked.','Heat sauce base (prepared as per recipe) in a pan.','Simmer gently and adjust consistency.','Keep warm for service.','Spread hot sauce in serving plate or bowl.','Place steamed momos on top.','Serve hot immediately.']::text[], null, null, '2026-06-20T09:30:00.000Z', null, '2026-06-01T09:00:00.000Z', '2026-06-01T09:00:00.000Z'),
('421efd3e-35cf-41ab-b3e6-930ec443f7ea', 'Cheese Chilli Dumplings', 'Dimsum', 'aiko', null, null, null, 5, 'approved', 106.28, 106.28, 480, 0, 5, false, 636.5, 'Gram', 1, ARRAY['PREPARE FILLING: Mix all filling ingredients thoroughly. Chill the filling for easy wrapping.','ASSEMBLE DUMPLINGS: Place required filling in the center of each wrapper. Seal edges tightly to form momos.','STEAM: Steam dumplings for 4-5 minutes until cooked.','PREPARE SAUCE: Blend or crush all sauce ingredients to a smooth paste. Heat in a pan and simmer. Adjust consistency and seasoning as required.','PLATE: Spread green sauce on the base of the plate. Place steamed dumplings on top.','GARNISH: Top with fried onion and pickled red Bhavnagri.']::text[], null, null, '2026-06-20T09:30:00.000Z', null, '2026-06-01T09:00:00.000Z', '2026-06-01T09:00:00.000Z'),
('d5182d56-df99-441e-9fb5-b705eba45ec0', 'Chilli Oil Dumplings', 'Dimsum', 'aiko', null, null, null, 5, 'approved', 62.35, 62.35, 620, 0, 5, false, 227, 'Gram', 1, ARRAY['Prepare filling: Mix all filling ingredients thoroughly. Refrigerate for 15-20 min for easier handling.','Make chilli oil dumplings paste: Blend all paste ingredients to a smooth, thick paste. Store in an airtight container.','Assemble dumplings: Place required filling in the center of each wrapper. Seal edges tightly to form dumplings.','Steam dumplings: Steam for 4-5 minutes until fully cooked.','Prepare sauce: Heat oil in a pan, add chilli paste and saute for 30 seconds. Add stock water, red chilli powder, salt, msg, stock powder and Sichuan powder. Stir well. Simmer for 2-3 minutes. Adjust seasoning.','Finish & plate: Spread hot sauce on serving plate. Place steamed dumplings on top. Garnish with toasted peanuts, white & green spring onion and fried glass noodles. Serve immediately.']::text[], null, null, '2026-06-20T09:30:00.000Z', null, '2026-06-01T09:00:00.000Z', '2026-06-01T09:00:00.000Z'),
('cd5e7292-3cc9-42b1-8462-75926bb111ea', 'New Dimsum Platter', 'Dimsum', 'aiko', null, null, null, 5, 'approved', 200.19, 200.19, 1640, 0, 5, false, 125, 'Gram', 1, ARRAY['Prepare Dumplings: Ensure all dim sums are prepared, sealed and ready to steam.','Steam Dumplings: Steam all dumplings for 4-5 minutes on medium heat until cooked.','Prepare Dips & Sauces: Portion dips and sauces as per the given gram weight in small bowls.','Assemble Platter: Arrange all dim sums in a bamboo steamer as shown. Place the dip bowls in the centre or alongside.','Serve: Serve hot immediately.']::text[], null, null, '2026-06-20T09:30:00.000Z', null, '2026-06-01T09:00:00.000Z', '2026-06-01T09:00:00.000Z'),
('7284ddce-4f6a-445a-8805-a473bdb52223', 'Avocado Roll', 'Sushi', 'aiko', null, null, null, 8, 'approved', 186.3, 186.3, 840, 0, 5, false, 464.4, 'Gram', 1, ARRAY['Cook sushi rice and season as per standard.','Cool to room temperature.','Slice avocado and cucumber into thin batons.','Keep cream cheese ready.','Place nori on bamboo mat, shiny side down.','Spread a thin, even layer of rice leaving 1 inch at the top.','Spread cream cheese in the centre.','Add cucumber and avocado.','Lift the mat and roll tightly from the bottom.','Seal the edge with a little water.','Brush roll with buffalo sauce.','Coat with black and white sesame seeds.','Use a sharp knife.','Cut into 8 equal pieces.','Clean the knife after each cut.','Top with thin avocado slices.','Add crispy rice paper piece.','Drizzle unagi sauce.']::text[], null, null, '2026-06-20T09:30:00.000Z', null, '2026-06-01T09:00:00.000Z', '2026-06-01T09:00:00.000Z'),
('74b43958-faf2-428a-9f91-605a03d78479', 'Dragon Roll', 'Sushi', 'aiko', null, null, null, 8, 'approved', 86.42, 86.42, 720, 0, 5, false, 253.4, 'Gram', 1, ARRAY['Cook sushi rice and season as per standard.','Cool to room temperature.','Slice red bell pepper into thin strips.','Trim and cut spring onion.','Ensure fried lotus stem is crisp and ready.','Keep cream cheese ready.','Place nori on bamboo mat, shiny side down.','Spread a thin, even layer of rice leaving 1 inch at the top.','Spread cream cheese in the centre.','Add red bell pepper, spring onion and fried lotus stem.','Lift the mat and roll tightly from the bottom.','Seal the edge with a little water.','Use a sharp knife.','Cut into 8 equal pieces.','Clean the knife after each cut.','Drizzle spicy mayo on top.','Spoon dragon sauce over mayo.','Ensure even topping on all pieces.']::text[], null, null, '2026-06-20T09:30:00.000Z', null, '2026-06-01T09:00:00.000Z', '2026-06-01T09:00:00.000Z'),
('5b702c15-0a8f-4d87-9e6e-d17fe8244a28', 'Volcano 1', 'Sushi', 'aiko', null, null, null, 8, 'approved', 72.39, 9.05, null, 0, 5, false, 362.4, 'Gram', 1, ARRAY['Cook sushi rice and season as per standard.','Cool to room temperature.','Slice red bell pepper and cucumber into thin strips.','Julienne carrot and spring onion.','Dice mango into small cubes.','Keep cream cheese ready.','Place nori on bamboo mat, shiny side down.','Spread a thin, even layer of rice leaving 1 inch at the top.','Spread cream cheese in the centre.','Add spring onion, carrot, red bell pepper, cucumber and mango.','Lift the mat and roll tightly from the bottom.','Seal the edge with a little water.','Use a sharp knife.','Cut into 8 equal pieces.','Clean the knife after each cut.','Add spicy mayo on top.','Sprinkle chilly crisps and oil.','Garnish with micro greens.']::text[], null, null, '2026-06-20T09:30:00.000Z', null, '2026-06-01T09:00:00.000Z', '2026-06-01T09:00:00.000Z'),
('bd52b38b-a8bc-4547-a00f-7f74516286f2', 'Gimbap 1', 'Sushi', 'aiko', null, null, null, 8, 'approved', 111.12, 111.12, 980, 0, 5, false, 325.2, 'Gram', 1, ARRAY['Cook sushi rice and season as per standard.','Allow rice to cool to room temperature.','Slice cucumber, carrot and pickled radish into thin strips.','Sauté spinach with soy sauce and garlic. Cool.','Cut tofu into strips and toss with soy sauce.','Slice unagi into strips.','Place nori sheet on bamboo mat, shiny side down.','Spread an even layer of rice leaving 1 inch gap at the top.','Arrange tofu, unagi, radish, cucumber, carrot and spinach horizontally.','Lift the mat and roll tightly from the bottom.','Press gently to form a firm roll.','Seal the edge with a little water.','Use a sharp knife.','Cut into 8 equal pieces.','Wipe blade after each cut.','Brush lightly with sesame oil.','Sprinkle sesame seeds if required.']::text[], null, null, '2026-06-20T09:30:00.000Z', null, '2026-06-01T09:00:00.000Z', '2026-06-01T09:00:00.000Z'),
('2c4e9fe6-643b-4d39-8803-497870f9a1d6', 'Bombay Blues Roll', 'Sushi', 'aiko', null, null, null, 8, 'approved', 70.92, 8.87, null, 0, 5, false, 311.4, 'Gram', 1, ARRAY['Cook sushi rice and season as per standard.','Allow rice to cool to room temperature.','Finely slice spring onion, carrot, cucumber, red capsicum and jalapeño.','Chop coriander.','Keep cream cheese ready.','Place nori on bamboo mat, shiny side down.','Spread an even layer of rice leaving 1 inch gap at the top.','In the center add cream cheese, spring onion, carrot, cucumber, red capsicum, jalapeño and coriander.','Lift the mat and roll tightly from the bottom.','Press gently to form a firm roll.','Seal the edge with a little water.','Use a sharp knife.','Cut into 8 equal pieces.','Clean the knife after each cut.','Top each piece with salsa and tempura flex.','Drizzle sweet chilli sauce, unagi sauce and sriracha.','Serve with soy sauce, pickled ginger and wasabi.']::text[], null, null, '2026-06-20T09:30:00.000Z', null, '2026-06-01T09:00:00.000Z', '2026-06-01T09:00:00.000Z'),
('0f389a77-0386-4a5c-849b-1a9311dc6ead', 'Jalapeño Popper Roll', 'Sushi', 'aiko', null, null, null, 8, 'approved', 78.23, 9.78, null, 0, 5, false, 264.4, 'Gram', 1, ARRAY['Cook sushi rice and season as per standard.','Allow rice to cool to room temperature.','Slice jalapeño into thin rings.','Finely chop coriander and spring onion.','Cut raw mango into thin julienne strips.','Keep cream cheese ready.','Place nori on bamboo mat, shiny side down.','Spread an even layer of rice leaving 1 inch gap at the top.','In the center add cream cheese, jalapeño, raw mango, spring onion and coriander.','Lift the mat and roll tightly from the bottom.','Press gently to form a firm roll.','Seal the edge with a little water.','Roll in fried spring roll for extra crunch.','Spread a thin layer of cream cheese.','Coat the roll evenly with bread crumbs.','Heat oil to 180°C and flash fry until golden and crisp.','Drain on paper towel.','Drizzle unagi sauce and sriracha on top.','Garnish with coriander and sesame seeds.','Slice 8 equal pieces using a sharp knife.','Clean the knife after each cut.']::text[], null, null, '2026-06-20T09:30:00.000Z', null, '2026-06-01T09:00:00.000Z', '2026-06-01T09:00:00.000Z'),
('70700fe0-486b-458a-a4ee-671801ffc886', 'Corn Tempura Roll', 'Sushi', 'aiko', null, null, null, 8, 'approved', 140.24, 140.24, 720, 0, 5, false, 399.8, 'Gram', 1, ARRAY['Cook sushi rice and season as per standard.','Allow rice to cool to room temperature.','Drain corn well.','Batter corn with tempura flour and deep fry until golden and crisp.','Slice cucumber and purple cabbage into thin juilenne strips.','Finely chop spring onion.','Keep cream cheese ready.','Place nori on bamboo mat, shiny side down.','Spread an even layer of rice leaving 1 inch gap at the top.','In the center add cream cheese, cucumber, purple cabbage, spring onion and corn tempura.','Roll tightly using mat, applying even pressure.','Moisten knife and slice into 8 equal pieces.','Clean knife after each cut.','Drizzle sriracha on top.','Serve with pickled ginger, wasabi and soy sauce.']::text[], null, null, '2026-06-20T09:30:00.000Z', null, '2026-06-01T09:00:00.000Z', '2026-06-01T09:00:00.000Z'),
('35e42b4f-050f-4224-8570-5d842444ae49', 'Fried Rice', 'Rice', 'aiko', null, null, null, 1, 'approved', 95.47, 95.47, 540, 0, 5, false, 380.4, 'Gram', 1, ARRAY['Heat wok on high heat until smoking.','Add oil, then ginger; sauté for 10–15 sec.','Add carrot, corn, edamame; toss for 60–90 sec.','Add cooked rice; toss until steamy hot.','Add stock powder, salt, white pepper, MSG; toss.','Add light soy; toss evenly.','Add spring onion; toss and plate immediately.']::text[], null, null, '2026-06-20T09:30:00.000Z', null, '2026-06-01T09:00:00.000Z', '2026-06-01T09:00:00.000Z'),
('0c17ffa7-09c9-4377-823e-4ba0a8305c2d', 'Burnt Garlic Fried Rice', 'Rice', 'aiko', null, null, null, 1, 'approved', 95.47, 95.47, 540, 0, 5, false, 424.4, 'Gram', 1, ARRAY['Heat wok on medium-high until hot.','Add oil, then garlic; sauté on medium until pale golden (do not burn).','Increase heat; add broccoli, baby corn and spinach; toss 60–90 sec.','Add cooked rice; toss on high heat until heated through.','Add stock powder, salt, white pepper and MSG; toss evenly.','Add light soy; toss evenly.','Plate and top with fried garlic and spring onion.']::text[], null, null, '2026-06-20T09:30:00.000Z', null, '2026-06-01T09:00:00.000Z', '2026-06-01T09:00:00.000Z'),
('7fba5bfa-3a49-451c-b74f-0d122291323d', 'Mushroom Truffle Fried Rice', 'Rice', 'aiko', null, null, null, 1, 'approved', 235.98, 235.98, 680, 0, 5, false, 410.6, 'Gram', 1, ARRAY['Heat wok on high until smoking.','Add oil and garlic; sauté for 10 sec until aromatic.','Add mushrooms; cook until moisture evaporates and mushrooms brown.','Add chili bean paste, oyster sauce and hot sauce; toss for 15-20 sec.','Add rice and edamame; toss on high heat until rice is hot and everything combined.','Add white pepper, truffle pâté and MSG; toss evenly.','Switch off heat; fold in truffle oil. Plate and serve immediately.']::text[], null, null, '2026-06-20T09:30:00.000Z', null, '2026-06-01T09:00:00.000Z', '2026-06-01T09:00:00.000Z'),
('f9deaed9-ead0-46b5-b332-9db81d8b991e', 'Hakka Noodles', 'Noodles', 'aiko', null, null, null, 1, 'approved', 36.96, 36.96, 580, 0, 5, false, 275.3, 'Gram', 1, ARRAY['Heat wok high until smoking.','Add oil and ginger-garlic; sauté 10-15 sec.','Add vegetables; toss 60-90 sec (keep crunchy).','Add noodles; toss to separate strands.','Add hakka sauce + stock powder, salt, white pepper, MSG; toss on high heat.','Finish spring onion; plate immediately.']::text[], null, null, '2026-06-20T09:30:00.000Z', null, '2026-06-01T09:00:00.000Z', '2026-06-01T09:00:00.000Z'),
('18c5039e-e481-446a-b270-697252b21375', 'Drunken Noodles', 'Noodles', 'aiko', null, null, null, 1, 'approved', 38.55, 38.55, 580, 0, 5, false, 269, 'Gram', 1, ARRAY['Heat wok high until smoking.','Add oil and garlic + chilli; sauté 10–15 sec.','Add mushrooms; toss until lightly browned.','Add spring onion whites; stir-fry briefly.','Add noodles + drunken sauce; toss until glossy.','Add bean sprouts + basil; toss 20–30 sec.','Plate immediately.']::text[], null, null, '2026-06-20T09:30:00.000Z', null, '2026-06-01T09:00:00.000Z', '2026-06-01T09:00:00.000Z'),
('78b80a62-93f1-4686-bcce-c7e634eee1b2', 'Pad Thai', 'Noodles', 'aiko', null, null, null, 1, 'approved', 65.61, 65.61, 580, 0, 5, false, 345, 'Gram', 1, ARRAY['Heat wok medium-high; add oil.','Add ginger-garlic; sauté 10 sec.','Add mushrooms and carrot; toss 60 sec.','Add noodles and pad thai sauce; toss until absorbed.','Add sprouts; toss 15–20 sec.','Plate and finish with spring onion, peanuts and coriander.','Serve with lemon wedge.']::text[], null, null, '2026-06-20T09:30:00.000Z', null, '2026-06-01T09:00:00.000Z', '2026-06-01T09:00:00.000Z'),
('252edbed-008a-4be9-a046-f4b4ecaada7d', 'Shoyu Ramen', 'Noodles', 'aiko', null, null, null, 1, 'approved', 42.6, 42.6, 640, 0, 5, false, 361, 'Gram', 1, ARRAY['Bring stock + dashi to gentle simmer.','Add shoyu tare + seasoning; simmer 3-4 min (no hard boil).','Cook noodles separately; drain well.','Place noodles in bowl; pour hot broth.','Top vegetables; finish sesame + scallion oil.']::text[], null, null, '2026-06-20T09:30:00.000Z', null, '2026-06-01T09:00:00.000Z', '2026-06-01T09:00:00.000Z'),
('ed2c55d8-7f64-4bd2-98ef-1f43cbb7d0ea', 'Peanut Butter Ramen', 'Noodles', 'aiko', null, null, null, 1, 'approved', 61.81, 61.81, 640, 0, 5, false, 606.5, 'Gram', 1, ARRAY['Heat oil; sauté ginger + garlic.','Add gochujang + chilli bean paste + chilli powder; bloom 30–40 sec.','Add water gradually; whisk smooth.','Add peanut butter; whisk until emulsified.','Season; simmer 2–3 min.','Cook noodles separately; assemble bowl.']::text[], null, null, '2026-06-20T09:30:00.000Z', null, '2026-06-01T09:00:00.000Z', '2026-06-01T09:00:00.000Z'),
('8d25724f-1ac3-4998-888d-582acddaa05f', 'Spiced Miso Ramen', 'Noodles', 'aiko', null, null, null, 1, 'approved', 47.47, 47.47, null, 0, 5, false, 692.5, 'Gram', 1, ARRAY['Heat oil in a pot over medium heat; add ginger and garlic paste, sauté until aromatic.','Add gochujang, chilli bean paste and chilli powder; bloom for 30–40 sec.','Gradually add water while whisking to avoid lumps.','Add peanut butter and whisk continuously until fully emulsified.','Season with stock powder, MSG, white pepper, salt and caster sugar. Simmer for 2–3 min.','Cook ramen noodles separately as per instructions; drain well.','Assemble the bowl with noodles and hot broth.','Top with peanuts, coriander, spring onion, edamame and pokchoy.','Drizzle with chilli oil and serve with lemon wedge.']::text[], null, null, '2026-06-20T09:30:00.000Z', null, '2026-06-01T09:00:00.000Z', '2026-06-01T09:00:00.000Z'),
('05e8f466-81e9-455d-b2fe-7e23724afbb5', 'Buttery Chilli Garlic Noodles', 'Noodles', 'aiko', null, null, null, 1, 'approved', 24.29, 24.29, 580, 0, 5, false, 211.8, 'Gram', 1, ARRAY['Melt butter on low heat.','Add garlic + chilli; cook gently until aromatic.','Add chilli crisp + seasoning; whisk with 10–15 ml hot water to emulsify.','Add noodles; toss until glossy and coated.','Plate; top with spring onion and fried garlic.']::text[], null, null, '2026-06-20T09:30:00.000Z', null, '2026-06-01T09:00:00.000Z', '2026-06-01T09:00:00.000Z'),
